50	class Runtime : public api::MemoryRef {
51	public:
52	    Runtime(uint64_t v) : api::MemoryRef(v) {}
53	    Runtime(uint64_t v, LoadBlock* b) : api::MemoryRef(v, b) {}
54	    Runtime(const api::MemoryRef& ref) : api::MemoryRef(ref) {}
55	    Runtime(uint64_t v, api::MemoryRef& ref) : api::MemoryRef(v, ref) {}
56	    Runtime(uint64_t v, api::MemoryRef* ref) : api::MemoryRef(v, ref) {}
57	
58	    inline bool operator==(Runtime& ref) { return Ptr() == ref.Ptr(); }
59	    inline bool operator!=(Runtime& ref) { return Ptr() != ref.Ptr(); }
60	
61	    static void Init();
62	    static void Init23();
63	    static void Init24();
64	    static void Init26();
65	    static void Init28();
66	    static void Init29();
67	    static void Init30();
68	    static void Init31();
69	    static void Init33();
70	    static void Init34();
71	    static void Init35();
72	    static void Init36();
73	    static void Init37();
74	    inline uint64_t callee_save_methods() { return Ptr() + OFFSET(Runtime, callee_save_methods_); }
75	    inline uint64_t resolution_method() { return VALUEOF(Runtime, resolution_method_); }
76	    inline uint64_t imt_conflict_method() { return VALUEOF(Runtime, imt_conflict_method_); }
77	    inline uint64_t imt_unimplemented_method() { return VALUEOF(Runtime, imt_unimplemented_method_); }
78	    inline uint64_t heap() { return VALUEOF(Runtime, heap_); }
79	    inline uint64_t monitor_pool() { return VALUEOF(Runtime, monitor_pool_); }
80	    inline uint64_t thread_list() { return VALUEOF(Runtime, thread_list_); }
81	    inline uint64_t class_linker() { return VALUEOF(Runtime, class_linker_); }
82	    inline uint64_t java_vm() { return VALUEOF(Runtime, java_vm_); }
83	    inline uint64_t jit() { return VALUEOF(Runtime, jit_); }
84	
85	    static Runtime& Current();
86	    static api::MemoryRef& Origin();
87	    gc::Heap& GetHeap();
88	    MonitorPool& GetMonitorPool();
89	    ThreadList& GetThreadList();
90	    ClassLinker& GetClassLinker();
91	    JavaVMExt& GetJavaVM();
92	    jit::Jit& GetJit();
93	    ArtMethod& GetResolutionMethod();
94	    ArtMethod& GetImtConflictMethod();
95	    ArtMethod& GetImtUnimplementedMethod();
96	    ArtMethod& GetCalleeSaveMethod(CalleeSaveType type);
97	    ArtMethod& GetCalleeSaveMethodUnchecked(CalleeSaveType type);
98	    QuickMethodFrameInfo GetRuntimeMethodFrameInfo(ArtMethod& method);
99	
100	    void CleanCache() {
101	        if (heap_cache.Ptr()) heap_cache.CleanCache();
102	        if (thread_list_cache.Ptr()) thread_list_cache.CleanCache();
103	        if (class_linker_cache.Ptr()) class_linker_cache.CleanCache();
104	        runtime_instance_ori_cache = 0x0;
105	        art::CacheHelper::Clean();
106	    }
107	private:
108	    static Runtime AnalysisInstance();
109	    static void AnalysisCalleeSaveMethods(uint64_t *callee_methods, uint32_t sizeof_callee_methods);
110	    static Runtime AnalysisRuntime(uint64_t *callee_methods, uint32_t sizeof_callee_methods);
111	    static api::MemoryRef runtime_instance_ori_cache;
112	    static uint32_t kNumCalleeMethodsCount;
113	    static inline uint32_t SizeOfCalleeMethods() { return kNumCalleeMethodsCount * sizeof(uint64_t); }
114	    // quick memoryref cache
115	    ArtMethod callee_save_methods_cache[6] = {0x0, 0x0, 0x0, 0x0, 0x0, 0x0};
116	    ArtMethod resolution_method_cache = 0x0;
117	    ArtMethod imt_conflict_method_cache = 0x0;
118	    ArtMethod imt_unimplemented_method_cache = 0x0;
119	    gc::Heap heap_cache = 0x0;
120	    MonitorPool monitor_pool_cache = 0x0;
121	    ThreadList thread_list_cache = 0x0;
122	    ClassLinker class_linker_cache = 0x0;
123	    JavaVMExt java_vm_cache = 0x0;
124	    jit::Jit jit_cache = 0x0;
125	};
