52	    inline bool operator!=(ArtField& ref) { return Ptr() != ref.Ptr(); }
53	
54	    static bool Compare(art::ArtField& a, art::ArtField& b) { return a.offset() > b.offset(); }
55	    static void Init();
56	    inline uint32_t declaring_class() { return *reinterpret_cast<uint32_t*>(Real() + OFFSET(ArtField, declaring_class_)); }
57	    inline uint32_t access_flags() { return *reinterpret_cast<uint32_t*>(Real() + OFFSET(ArtField, access_flags_)); }
58	    inline uint32_t field_dex_idx() { return *reinterpret_cast<uint32_t*>(Real() + OFFSET(ArtField, field_dex_idx_)); }
59	    inline uint32_t offset() { return *reinterpret_cast<uint32_t*>(Real() + OFFSET(ArtField, offset_)); }
60	
61	    inline bool IsStatic() { return (GetAccessFlags() & kAccStatic) != 0; }
62	    inline bool IsProxyField() { return GetDeclaringClass().IsProxyClass(); }
63	    inline const char* GetTypeDescriptor() { return GetTypeDescriptor("B"); }
64	    const char* GetTypeDescriptor(const char* def);
65	    std::string PrettyTypeDescriptor();
66	    inline mirror::Class& GetDeclaringClass() { return QUICK_CACHE(declaring_class); }
67	    inline uint32_t GetDexFieldIndex() { return field_dex_idx(); }
68	    inline mirror::DexCache& GetDexCache() { return GetDeclaringClass().GetDexCache(); }
